test-case.script:
var t = debug.assert;

var result = false;
if (1) result = true;
t(result == true);

result = false;
if ("hello") result = true;
t(result == true);

result = false;
var obj = {};
if (obj) result = true;
t(result == true);

result = false;
if (-1) result = true;
t(result == true);

result = false;
if (0.5) result = true;
t(result == true);

var t = debug.assert;

var result = true;
if (0) result = false;
t(result == true);

result = true;
if (null) result = false;
t(result == true);

result = true;
if ("") result = false;
t(result == true);

var t = debug.assert;

t(!null == true);
t(!0 == true);
t(!"" == true);

t(!1 == false);
t(!"hello" == false);
t(!{} == false);

var t = debug.assert;

var a = null;
var b = a || "default";
t(b, "default");

var c = "value";
var d = c || "default";
t(d, "value");

var e = 0;
var f = e || 42;
t(f, 42);

var t = debug.assert;

var a = null;
var b = a && "hello";
t(b == null);

var c = "value";
var d = c && "hello";
t(d, "hello");

var e = 1;
var f = e && 42;
t(f, 42);

var t = debug.assert;

var a = 1 ? "yes" : "no";
t(a, "yes");

var b = 0 ? "yes" : "no";
t(b, "no");

var c = "str" ? "yes" : "no";
t(c, "yes");

var d = null ? "yes" : "no";
t(d, "no");

var t = debug.assert;

var count = 5;
var sum = 0;
while (count) {
  sum += count;
  count--;
}
t(sum, 15);

var t = debug.assert;

var sum = 0;
for (var arr = [1,2,3], i = arr.length; i; i--) {
  sum += arr[i - 1];
}
t(sum, 6);
